/* eslint-disable @next/next/no-img-element */
"use client";

import Link from "next/link";

import { useStorefront } from "@/components/providers/StorefrontProvider";
import { formatIQD, getProductName } from "@/lib/storefront";
import type { Product } from "@/lib/types";
import { useCartStore } from "@/store/cart";

type ProductCardProps = {
  product: Product;
};

export function ProductCard({ product }: ProductCardProps) {
  const addItem = useCartStore((state) => state.addItem);
  const { language, isRTL } = useStorefront();

  return (
    <article className="group flex h-full flex-col overflow-hidden rounded-xl border border-slate-200 bg-white transition duration-200 hover:border-slate-300">
      <Link href={`/product/${product.id}`} className="block">
        <div className="overflow-hidden bg-slate-100">
          <img
            src={product.image_url}
            alt={getProductName(product, language)}
            className="aspect-[4/4.8] w-full object-cover transition duration-500 group-hover:scale-[1.03]"
            loading="lazy"
          />
        </div>
      </Link>

      <div className="flex flex-1 flex-col gap-2 p-3">
        <div className={isRTL ? "text-right" : "text-left"}>
          <Link
            href={`/product/${product.id}`}
            className="line-clamp-2 text-sm font-semibold tracking-tight text-[#1D1D1F] sm:text-base"
          >
            {getProductName(product, language)}
          </Link>
          <p
            className={`mt-2 text-xs font-medium ${
              product.stock_quantity > 0 ? "text-primary" : "text-slate-500"
            }`}
          >
            {product.stock_quantity > 0
              ? language === "ar"
                ? "متوفر"
                : "In stock"
              : language === "ar"
                ? "غير متوفر"
                : "Out of stock"}
          </p>
        </div>

        <p className={isRTL ? "text-right text-lg font-semibold text-[#1D1D1F]" : "text-left text-lg font-semibold text-[#1D1D1F]"}>
          {formatIQD(product.price_iqd, language)}
        </p>

        <button
          type="button"
          onClick={() => addItem(product)}
          disabled={product.stock_quantity <= 0}
          className={`mt-auto inline-flex min-h-11 w-full items-center justify-center rounded-[0.625rem] px-4 py-2.5 text-sm font-semibold transition ${
            product.stock_quantity > 0
              ? "bg-primary text-white hover:bg-primary/95"
              : "cursor-not-allowed bg-slate-200 text-slate-500"
          }`}
        >
          <span>{language === "ar" ? "أضف إلى السلة" : "Add to cart"}</span>
        </button>
      </div>
    </article>
  );
}
